UPDATE hpeapm.audit_elements_info a SET primary_business_process = b.primary_business_process_new FROM ( SELECT * FROM hpeapm.model_msg_update WHERE primary_business_process_type = '是' ) b WHERE a.audit_model_number = b.audit_model_number; UPDATE hpeapm.audit_elements_info a SET secondary_business_process = b.secondary_business_process_new FROM ( SELECT * FROM hpeapm.model_msg_update WHERE secondary_business_process_type = '是' ) b WHERE a.audit_model_number = b.audit_model_number; UPDATE hpeapm.audit_elements_info a SET audit_point_name = b.audit_point_name_new FROM ( SELECT * FROM hpeapm.model_msg_update WHERE audit_point_name_type = '是' ) b WHERE a.audit_model_number = b.audit_model_number;
UPDATE hpeapm."audit_elements_operation_steps" a, (SELECT * FROM hpeapm."model_msg_update" WHERE audit_point_name_type = '是') b SET a.audit_point_name = b.audit_point_name_new WHERE a.audit_model_number = b.audit_model_number;
UPDATE hpeapm."spl_model_type" a, (SELECT * FROM hpeapm."model_msg_update" WHERE audit_point_name_type = '是') b SET a.audit_point_name = b.audit_point_name_new WHERE a.audit_model_number = b.audit_model_number;
UPDATE hpeapm."audit_elements_info" a, (SELECT * FROM hpeapm."model_msg_update" WHERE audit_model_name_type = '是') b SET a.audit_model_name = b.audit_model_name_new WHERE a.audit_model_number = b.audit_model_number; UPDATE hpeapm."audit_elements_operation_steps" a, (SELECT * FROM hpeapm."model_msg_update" WHERE audit_model_name_type = '是') b SET a.audit_model_name = b.audit_model_name_new WHERE a.audit_model_number = b.audit_model_number; UPDATE hpeapm."spl_model_type" a, (SELECT * FROM hpeapm."model_msg_update" WHERE audit_model_name_type = '是') b SET a.audit_model_name = b.audit_model_name_new WHERE a.audit_model_number = b.audit_model_number; UPDATE hpeapm."audit_elements_info" a, (SELECT * FROM hpeapm."model_msg_update" WHERE audit_point_number_type = '是') b SET a.audit_point_number = b.audit_point_number_new WHERE a.audit_model_number = b.audit_model_number;
UPDATE hpeapm."audit_elements_operation_steps" a, (SELECT * FROM hpeapm."model_msg_update" WHERE audit_point_number_type = '是') b SET a.audit_point_number = b.audit_point_number_new WHERE a.audit_model_number = b.audit_model_number; UPDATE hpeapm."spl_model_type" a, (SELECT * FROM hpeapm."model_msg_update" WHERE audit_point_number_type = '是') b SET a.audit_point_number = b.audit_point_number_new WHERE a.audit_model_number = b.audit_model_number;

